   153	func (v QueryValue) ColumnNames() []string {
   154		if v.Struct == nil {
   155			return []string{v.DBName}
   156		}
   157		names := make([]string, len(v.Struct.Fields))
   158		for i, f := range v.Struct.Fields {
   159			names[i] = f.DBName
   160		}
   161		return names
   162	}
