   164	func (v QueryValue) ColumnNamesAsGoSlice() string {
   165		if v.Struct == nil {
   166			return fmt.Sprintf("[]string{%q}", v.DBName)
   167		}
   168		escapedNames := make([]string, len(v.Struct.Fields))
   169		for i, f := range v.Struct.Fields {
   170			if f.Column != nil && f.Column.OriginalName != "" {
   171				escapedNames[i] = fmt.Sprintf("%q", f.Column.OriginalName)
   172			} else {
   173				escapedNames[i] = fmt.Sprintf("%q", f.DBName)
   174			}
   175		}
   176		return "[]string{" + strings.Join(escapedNames, ", ") + "}"
   177	}
