   247	func (v QueryValue) VariableForField(f Field) string {
   248		if !v.IsStruct() {
   249			return v.Name
   250		}
   251		if !v.EmitStruct() {
   252			return toLowerCase(f.Name)
   253		}
   254		return v.Name + "." + f.Name
