   272	func (q Query) hasRetType() bool {
   273		scanned := q.Cmd == metadata.CmdOne || q.Cmd == metadata.CmdMany ||
   274			q.Cmd == metadata.CmdBatchMany || q.Cmd == metadata.CmdBatchOne
   275		return scanned && !q.Ret.isEmpty()
   276	}
