   356	func checkNoTimesForMySQLCopyFrom(queries []Query) error {
   357		for _, q := range queries {
   358			if q.Cmd != metadata.CmdCopyFrom {
   359				continue
   360			}
   361			for _, f := range q.Arg.CopyFromMySQLFields() {
   362				if f.Type == "time.Time" {
